const input = $input.first().json;
const city = input.city || 'Berlin';

const geo = await helpers.httpRequest({
  method: 'GET',
  url: 'https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(city) + '&count=1&language=en'
});

if (!geo.results || geo.results.length === 0) {
  return [{ json: { error: 'City not found: ' + city } }];
}

const lat = geo.results[0].latitude;
const lon = geo.results[0].longitude;
const name = geo.results[0].name;

const w = await helpers.httpRequest({
  method: 'GET',
  url: 'https://api.open-meteo.com/v1/forecast?latitude=' + lat + '&longitude=' + lon + '&current_weather=true&daily=temperature_2m_max,temperature_2m_min,precipitation_probability_max,windspeed_10m_max&timezone=auto&forecast_days=3'
});

const cw = w.current_weather;
const d = w.daily;
let r = name + ': ' + cw.temperature + 'C, Wind ' + cw.windspeed + ' km/h\n';
const labels = ['today', 'tomorrow', 'day after tomorrow'];
for (let i = 0; i < 3; i++) {
  r += labels[i] + ': ' + d.temperature_2m_min[i] + '-' + d.temperature_2m_max[i] + 'C, ' + d.precipitation_probability_max[i] + '% rain, Wind ' + d.windspeed_10m_max[i] + ' km/h\n';
}

return [{ json: { result: r } }];
